    def shell_complete(self, ctx: Context, incomplete: str) -> list[CompletionItem]:
        """Return completions for this option. A manually provided
        ``shell_complete`` callback always takes precedence. Otherwise,
        if ``auto_complete`` is enabled, :meth:`_smart_complete` is used
        to determine context-aware completions based on the option's
        name. Falls back to the option's :attr:`type` completions.

        .. versionadded:: 8.3
        """
        if self._custom_shell_complete is None and self.auto_complete:
            return self._smart_complete(ctx, incomplete)

        return super().shell_complete(ctx, incomplete)

    def _smart_complete(self, ctx: Context, incomplete: str) -> list[CompletionItem]:
        """Determine completions automatically from the option's name.

        Looks up the option's name against a registry of common
        patterns (usernames, git branches, filesystem paths,
        environment variables) and falls back to the option's
        :attr:`type` completions if no pattern matches.

        .. versionadded:: 8.3
        """
        name = (self.name or "").lower()

        for pattern, complete_func in _AUTO_COMPLETE_REGISTRY.items():
            if pattern in name:
                return complete_func(ctx, self, incomplete)

        return self.type.shell_complete(ctx, self, incomplete)

