def _complete_usernames(
    ctx: Context, param: Parameter, incomplete: str
) -> list[CompletionItem]:
    from click.shell_completion import CompletionItem

    try:
        import pwd

        names = [entry.pw_name for entry in pwd.getpwall()]
    except (ImportError, OSError):
        names = []

    return [CompletionItem(name) for name in names if name.startswith(incomplete)]


def _complete_git_branches(
    ctx: Context, param: Parameter, incomplete: str
) -> list[CompletionItem]:
    import subprocess

    from click.shell_completion import CompletionItem

    try:
        output = subprocess.run(
            ["git", "branch", "-a", "--format=%(refname:short)"],
            capture_output=True,
            text=True,
            check=True,
        ).stdout
    except (OSError, subprocess.SubprocessError):
        return []

    branches = {line.strip() for line in output.splitlines() if line.strip()}
    return [
        CompletionItem(branch) for branch in branches if branch.startswith(incomplete)
    ]


def _complete_filesystem_paths(
    ctx: Context, param: Parameter, incomplete: str
) -> list[CompletionItem]:
    from click.shell_completion import CompletionItem

    return [CompletionItem(incomplete, type="file")]


def _complete_env_vars(
    ctx: Context, param: Parameter, incomplete: str
) -> list[CompletionItem]:
    from click.shell_completion import CompletionItem

    return [name for name in os.environ if name.startswith(incomplete)] and [
        CompletionItem(name) for name in os.environ if name.startswith(incomplete)
    ]


#: Maps substrings of an option's name to a function that returns
#: shell completions for it. Used by :meth:`Option._smart_complete`
